using BookLoans.Abstractions.Models;using BookLoans.Abstractions.Extensions;using BookLoans.Abstractions.Interfaces;using BookLoans.Data.Entities;using Microsoft.EntityFrameworkCore;namespace BookLoans.Data.Repositories;public class AdminBookRepository(AppDbContext dbContext) : IAdminBookRepository{    public async Task<IReadOnlyList<Book>> GetBooksAsync(CancellationToken ct)    {        List<BookEntity> entities = await dbContext.Books            .AsNoTracking()            .Include(book => book.ConditionEntity)            .Include(book => book.CurrentBorrower)            .Include(book => book.Loans)            .Include(book => book.Photos)            .Include(book => book.BookAuthors)            .ThenInclude(bookAuthor => bookAuthor.AuthorEntity)            .OrderBy(book => book.Title)            .ToListAsync(ct);        return entities            .Select(book => book.ToAdminBookListItemDto())            .ToList();    }    public async Task<Book> GetCreateFormAsync(CancellationToken ct)    {        IReadOnlyList<Author> authors = await GetAuthorsAsync(ct);        IReadOnlyList<Condition> conditions = await GetConditionsAsync(ct);        return new Book        {            Authors = authors,            Conditions = conditions,            YearFirstPublished = DateTime.UtcNow.Year,            ConditionId = conditions.FirstOrDefault()?.Id ?? 0        };    }    public async Task<Book?> GetEditFormAsync(int id, CancellationToken ct)    {        BookEntity? book = await dbContext.Books            .AsNoTracking()            .Include(entity => entity.Loans)            .ThenInclude(loan => loan.BorrowerEntity)            .Include(entity => entity.Photos)            .Include(entity => entity.BookAuthors)            .ThenInclude(ba => ba.AuthorEntity)            .FirstOrDefaultAsync(entity => entity.Id == id, ct);        if (book is null)        {            return null;        }        return new Book        {            Id = book.Id,            Title = book.Title,            SelectedAuthorIds = await dbContext.BookAuthors                .AsNoTracking()                .Where(entity => entity.BookId == id)                .OrderBy(entity => entity.AuthorEntity.Name)                .Select(entity => entity.AuthorId)                .ToListAsync(ct),            Edition = book.Edition,            YearFirstPublished = book.YearFirstPublished,            YearEditionPublished = book.YearEditionPublished,            Isbn = book.Isbn,            DateOfPurchase = book.DateOfPurchase,            LocationOfPurchase = book.LocationOfPurchase,            ConditionId = book.ConditionId,            Authors = await GetAuthorsAsync(ct),            Conditions = await GetConditionsAsync(ct),            CurrentCheckout = book.Loans                .Where(loan => loan.ReturnedAtUtc == null)                .OrderByDescending(loan => loan.CheckedOutAtUtc)                .Select(loan => loan.ToBookLoanDto())                .FirstOrDefault(),            CheckoutHistory = book.Loans                .OrderByDescending(loan => loan.CheckedOutAtUtc)                .Select(loan => loan.ToBookLoanDto())                .ToList(),            BookPhotos = book.Photos                .OrderBy(photo => photo.SortOrder)                .ThenBy(photo => photo.Id)                .Select((photo, index) => photo.ToAdminBookPhotoItemDto(index == 0))                .ToList()        };    }    public async Task<string?> SetDefaultPhotoAsync(int bookId, int photoId, CancellationToken ct)    {        List<BookPhotoEntity> photos = await dbContext.BookPhotos            .Where(photo => photo.BookId == bookId)            .OrderBy(photo => photo.SortOrder)            .ThenBy(photo => photo.Id)            .ToListAsync(ct);        if (photos.Count == 0)        {            return "No photos found for this book.";        }        BookPhotoEntity? selectedPhoto = photos            .FirstOrDefault(photo => photo.Id == photoId);        if (selectedPhoto is null)        {            return "Photo not found.";        }        List<BookPhotoEntity> reorderedPhotos = photos            .Where(photo => photo.Id == photoId)            .Concat(photos.Where(photo => photo.Id != photoId))            .ToList();        for (int i = 0; i < reorderedPhotos.Count; i++)        {            reorderedPhotos[i].SortOrder = i;        }        await dbContext.SaveChangesAsync(ct);        return null;    }    public async Task<string?> UploadPhotoAsync(int bookId, BookPhoto? photo, CancellationToken ct)    {        BookEntity? book = await dbContext.Books            .Include(entity => entity.Photos)            .FirstOrDefaultAsync(entity => entity.Id == bookId, ct);        if (book is null)        {            return "BookEntity not found.";        }        if (photo is null || photo.Content.Length == 0)        {            return "Please select an image file to upload.";        }        string? normalizedMimeType = photo.MimeType.NormalizeOrNull();        if (normalizedMimeType is null || !normalizedMimeType.StartsWith("image/", StringComparison.OrdinalIgnoreCase))        {            return "Only image uploads are supported.";        }        string? normalizedCaption = photo.Caption.NormalizeOrNull();        if (normalizedCaption is not null && normalizedCaption.Length > 500)        {            return "Photo caption must be 500 characters or fewer.";        }        int sortOrder = book.Photos.Count == 0            ? 0            : book.Photos.Max(entity => entity.SortOrder) + 1;        BookPhotoEntity bookPhoto = new()        {            BookId = bookId,            Content = photo.Content,            Caption = normalizedCaption,            SortOrder = sortOrder,            UploadedAtUtc = DateTime.UtcNow,            MimeType = normalizedMimeType,            ByteLength = photo.Content.LongLength        };        dbContext.BookPhotos.Add(bookPhoto);        await dbContext.SaveChangesAsync(ct);        return null;    }    public async Task<string?> DeletePhotoAsync(int bookId, int photoId, CancellationToken ct)    {        BookPhotoEntity? photo = await dbContext.BookPhotos            .FirstOrDefaultAsync(entity => entity.Id == photoId && entity.BookId == bookId, ct);        if (photo is null)        {            return "Photo not found.";        }        dbContext.BookPhotos.Remove(photo);        await dbContext.SaveChangesAsync(ct);        return null;    }    public async Task<BookPhoto?> GetPhotoContentAsync(int photoId, CancellationToken ct)    {        BookPhotoEntity? photo = await dbContext.BookPhotos            .AsNoTracking()            .FirstOrDefaultAsync(p => p.Id == photoId, ct);        return photo?.ToContentDto();    }    public async Task<BookPhoto?> GetDefaultPhotoContentAsync(int bookId, CancellationToken ct)    {        BookPhotoEntity? photo = await dbContext.BookPhotos            .AsNoTracking()            .Where(p => p.BookId == bookId)            .OrderBy(p => p.SortOrder)            .ThenBy(p => p.Id)            .FirstOrDefaultAsync(ct);        return photo?.ToContentDto();    }    public async Task<string?> CreateAsync(Book model, CancellationToken ct)    {        string? normalizedIsbn = model.Isbn.NormalizeOrNull();        bool isbnExists = normalizedIsbn is not null && await dbContext.Books            .AnyAsync(book => book.Isbn == normalizedIsbn, ct);        if (isbnExists)        {            return "A book with this ISBN already exists.";        }        bool conditionExists = await dbContext.Conditions            .AnyAsync(condition => condition.Id == model.ConditionId, ct);        if (!conditionExists)        {            return "Please select a valid condition.";        }        (IReadOnlyList<int> authorIds, string? authorError) = await ResolveAuthorIdsAsync(model.SelectedAuthorIds, model.NewAuthorNames, ct);        if (authorError is not null)        {            return authorError;        }        BookEntity book = BookEntity.FromFormDto(model);        book.Isbn = normalizedIsbn;        dbContext.Books.Add(book);        foreach (int authorId in authorIds)        {            dbContext.BookAuthors.Add(new BookAuthorEntity            {                BookEntity = book,                AuthorId = authorId            });        }        await dbContext.SaveChangesAsync(ct);        return null;    }    public async Task<string?> UpdateAsync(int id, Book model, CancellationToken ct)    {        BookEntity? book = await dbContext.Books            .FirstOrDefaultAsync(entity => entity.Id == id, ct);        if (book is null)        {            return "BookEntity not found.";        }        string? normalizedIsbn = model.Isbn.NormalizeOrNull();        bool isbnExists = normalizedIsbn is not null && await dbContext.Books            .AnyAsync(entity => entity.Id != id && entity.Isbn == normalizedIsbn, ct);        if (isbnExists)        {            return "A book with this ISBN already exists.";        }        bool conditionExists = await dbContext.Conditions            .AnyAsync(condition => condition.Id == model.ConditionId, ct);        if (!conditionExists)        {            return "Please select a valid condition.";        }        (IReadOnlyList<int> authorIds, string? authorError) = await ResolveAuthorIdsAsync(model.SelectedAuthorIds, model.NewAuthorNames, ct);        if (authorError is not null)        {            return authorError;        }        book.Title = model.Title;        book.Edition = model.Edition;        book.YearFirstPublished = model.YearFirstPublished;        book.YearEditionPublished = model.YearEditionPublished;        book.Isbn = normalizedIsbn;        book.DateOfPurchase = model.DateOfPurchase;        book.LocationOfPurchase = model.LocationOfPurchase;        book.ConditionId = model.ConditionId;        List<BookAuthorEntity> existingBookAuthors = await dbContext.BookAuthors            .Where(entity => entity.BookId == id)            .ToListAsync(ct);        foreach (BookAuthorEntity bookAuthor in existingBookAuthors)        {            if (!authorIds.Contains(bookAuthor.AuthorId))            {                dbContext.BookAuthors.Remove(bookAuthor);            }        }        IReadOnlyCollection<int> existingAuthorIds = existingBookAuthors            .Select(entity => entity.AuthorId)            .ToList();        foreach (int authorId in authorIds)        {            if (!existingAuthorIds.Contains(authorId))            {                dbContext.BookAuthors.Add(new BookAuthorEntity                {                    BookId = id,                    AuthorId = authorId                });            }        }        await dbContext.SaveChangesAsync(ct);        return null;    }    public async Task<string?> DeleteAsync(int id, CancellationToken ct)    {        BookEntity? book = await dbContext.Books            .FirstOrDefaultAsync(entity => entity.Id == id, ct);        if (book is null)        {            return "BookEntity not found.";        }        dbContext.Books.Remove(book);        await dbContext.SaveChangesAsync(ct);        return null;    }    private async Task<IReadOnlyList<Condition>> GetConditionsAsync(CancellationToken ct)    {        List<ConditionEntity> conditions = await dbContext.Conditions            .AsNoTracking()            .Include(condition => condition.Books)            .OrderBy(condition => condition.Name)            .ToListAsync(ct);        return conditions            .Select(condition => condition.ToConditionDto())            .ToList();    }    private async Task<IReadOnlyList<Author>> GetAuthorsAsync(CancellationToken ct)    {        List<AuthorEntity> authors = await dbContext.Authors            .AsNoTracking()            .Include(author => author.BookAuthors)            .OrderBy(author => author.Name)            .ToListAsync(ct);        return authors            .Select(author => author.ToAuthorDto())            .ToList();    }    private async Task<(IReadOnlyList<int> authorIds, string? error)> ResolveAuthorIdsAsync(        IReadOnlyList<int> existingAuthorIds,        string? newAuthorNames,        CancellationToken ct)    {        List<int> resolvedAuthorIds = existingAuthorIds            .Distinct()            .ToList();        List<string> parsedNewAuthorNames = ParseNewAuthorNames(newAuthorNames);        foreach (string parsedName in parsedNewAuthorNames)        {            AuthorEntity? existingAuthor = await dbContext.Authors                .FirstOrDefaultAsync(author => author.Name == parsedName, ct);            if (existingAuthor is not null)            {                if (!resolvedAuthorIds.Contains(existingAuthor.Id))                {                    resolvedAuthorIds.Add(existingAuthor.Id);                }                continue;            }            AuthorEntity newAuthor = new()            {                Name = parsedName            };            dbContext.Authors.Add(newAuthor);            await dbContext.SaveChangesAsync(ct);            resolvedAuthorIds.Add(newAuthor.Id);        }        if (resolvedAuthorIds.Count == 0)        {            return ([], "Please select at least one author or enter a new author name.");        }        List<int> validAuthorIds = await dbContext.Authors            .AsNoTracking()            .Where(author => resolvedAuthorIds.Contains(author.Id))            .Select(author => author.Id)            .ToListAsync(ct);        if (validAuthorIds.Count != resolvedAuthorIds.Count)        {            return ([], "Please select valid authors.");        }        return (resolvedAuthorIds, null);    }    private static List<string> ParseNewAuthorNames(string? authorNames)    {        if (string.IsNullOrWhiteSpace(authorNames))        {            return [];        }        return authorNames            .Split(['\n'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)            .Where(name => !string.IsNullOrWhiteSpace(name))            .Distinct(StringComparer.OrdinalIgnoreCase)            .ToList();    }}